/* ─── TOAST CONTEXT ──────────────────────────────────────────── */
const ToastCtx = React.createContext({ showToast: () => {} });
const ToastProvider = ({ children }) => {
    const [toasts, setToasts] = React.useState([]);
    const idRef = React.useRef(0);
    const showToast = React.useCallback((msg, type = "success") => {
        const id = ++idRef.current;
        setToasts(prev => [...prev, { id, msg, type }]);
        setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
    }, []);
    const iconMap = { success: "Check", error: "X", info: "AlertTriangle", warning: "AlertTriangle" };
    const colorMap = { success: () => C.success, error: () => C.danger, info: () => C.info, warning: () => C.warning };
    const bgMap = { success: () => C.successBg, error: () => C.dangerBg, info: () => C.infoBg, warning: () => C.warningBg };
    const borderMap = { success: () => C.successBorder, error: () => C.dangerBorder, info: () => C.infoBorder, warning: () => C.warningBorder };
    return (
        <ToastCtx.Provider value={{ showToast }}>
            {children}
            <div style={{ position: "fixed", top: 20, right: 20, zIndex: 9999, display: "flex", flexDirection: "column", gap: 8, pointerEvents: "none" }}>
                <AnimatePresence>
                    {toasts.map(t => {
                        const LIcon = Lucide[iconMap[t.type]] || Lucide.Check;
                        return (
                            <motion.div key={t.id} initial={{ opacity: 0, x: 60, scale: 0.95 }} animate={{ opacity: 1, x: 0, scale: 1 }} exit={{ opacity: 0, x: 60, scale: 0.95 }} transition={{ duration: 0.25, ease: "easeOut" }}
                                style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 18px", background: bgMap[t.type](), border: `1px solid ${borderMap[t.type]()}`, borderRadius: 12, boxShadow: C.shadowMd, minWidth: 260, maxWidth: 380, pointerEvents: "auto" }}>
                                <div style={{ width: 28, height: 28, borderRadius: 8, background: `${colorMap[t.type]()}18`, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                                    <LIcon size={14} color={colorMap[t.type]()} />
                                </div>
                                <span style={{ fontSize: 13, fontWeight: 600, color: colorMap[t.type](), lineHeight: 1.4 }}>{t.msg}</span>
                            </motion.div>
                        );
                    })}
                </AnimatePresence>
            </div>
        </ToastCtx.Provider>
    );
};
const useToast = () => React.useContext(ToastCtx);

