const Avatar = ({ name, size = 32, color }) => {
    const colors = ["#6366F1", "#3B82F6", "#10B981", "#F59E0B", "#EF4444", "#8B5CF6", "#0891B2", "#D97706"];
    const initials = name ? name.split(" ").map(w => w[0]).join("").slice(0, 2).toUpperCase() : "??";
    const bg = color || colors[name?.charCodeAt(0) % colors.length] || C.primary;
    return (
        <div
            style={{ width: size, height: size, borderRadius: size * 0.35, background: bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.38, fontWeight: 700, color: "#fff", flexShrink: 0, letterSpacing: "-0.3px" }}
        >
            {initials}
        </div>
    );
};

const Input = ({ placeholder, value, onChange, style: sx, type = "text" }) => (
    <input
        type={type}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        style={{ padding: "8px 12px", border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, color: C.text, outline: "none", background: C.white, width: "100%", boxSizing: "border-box", fontFamily: "inherit", transition: "border-color 0.2s", ...sx }}
    />
);

const Select = ({ options, style: sx, value, onChange }) => (
    <div style={{ position: "relative", ...sx }}>
        <select
            value={value}
            onChange={onChange}
            style={{ padding: "8px 32px 8px 12px", border: `1px solid ${C.border}`, borderRadius: 8, fontSize: 13, color: C.text, outline: "none", background: C.white, fontFamily: "inherit", cursor: "pointer", appearance: "none", width: "100%", transition: "all 0.2s" }}
        >
            {options.map(o => typeof o === 'object' && o !== null
                ? <option key={o.value} value={o.value}>{o.label}</option>
                : <option key={o} value={o}>{o}</option>
            )}
        </select>
        <div style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", pointerEvents: "none", color: C.textMuted }}>
            <Icon n="chevDown" size={12} />
        </div>
    </div>
);

/* ─── BAR CHART (CSS only) ────────────────────────────────────── */
const BarChart = ({ data, color = C.primary, height = 80 }) => {
    const max = Math.max(...data.map(d => d.v));
    return (
        <div style={{ display: "flex", alignItems: "flex-end", gap: 6, height, paddingTop: 8 }}>
            {data.map((d, i) => (
                <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
                    <div style={{ width: "100%", height: Math.round((d.v / max) * (height - 20)), background: color, borderRadius: "4px 4px 0 0", opacity: d.active ? 1 : 0.35, transition: "height 0.4s ease" }} />
                    <span style={{ fontSize: 10, color: C.textMuted, fontWeight: 500 }}>{d.l}</span>
                </div>
            ))}
        </div>
    );
};

/* ─── DONUT CHART (SVG) ───────────────────────────────────────── */
const DonutChart = ({ segments, size = 80 }) => {
    const r = 30, cx = 40, cy = 40, circ = 2 * Math.PI * r;
    let offset = 0;
    const arcs = segments.map(s => {
        const dash = (s.pct / 100) * circ;
        const arc = { ...s, dash, offset };
        offset += dash;
        return arc;
    });
    return (
        <svg width={size} height={size} viewBox="0 0 80 80">
            <circle cx={cx} cy={cy} r={r} fill="none" stroke={C.borderLight} strokeWidth={10} />
            {arcs.map((a, i) => (
                <circle key={i} cx={cx} cy={cy} r={r} fill="none" stroke={a.color} strokeWidth={10}
                    strokeDasharray={`${a.dash} ${circ - a.dash}`} strokeDashoffset={-a.offset}
                    transform="rotate(-90 40 40)" strokeLinecap="round" style={{ transition: "stroke-dasharray 0.4s" }} />
            ))}
        </svg>
    );
};

/* ─── MODAL COMPONENT ─────────────────────────────────────────── */
const Modal = ({ isOpen, onClose, title, children }) => {
    return (
        <AnimatePresence>
            {isOpen && (
                <div style={{ position: "fixed", inset: 0, zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        style={{ position: "absolute", inset: 0, background: "rgba(15, 23, 42, 0.4)", backdropFilter: "blur(8px)" }}
                    />
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: 20 }}
                        transition={{ type: "spring", damping: 25, stiffness: 300 }}
                        style={{ position: "relative", width: "100%", maxWidth: 840, maxHeight: "90vh", background: C.white, borderRadius: 20, boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25)", overflow: "hidden", display: "flex", flexDirection: "column" }}
                    >
                        <div style={{ padding: "20px 24px", borderBottom: `1px solid ${C.borderLight}`, display: "flex", alignItems: "center", justifyContent: "space-between", background: C.white }}>
                            <h2 style={{ fontSize: 18, fontWeight: 800, color: C.text, margin: 0, letterSpacing: "-0.4px" }}>{title}</h2>
                            <Btn variant="ghost" size="sm" onClick={onClose} style={{ borderRadius: "50%", padding: 6 }}>
                                <Icon n="close" size={20} />
                            </Btn>
                        </div>
                        <div style={{ overflowY: "auto", flex: 1 }}>
                            {children}
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
};

