const INITIAL_ATTENDANCE = (() => {
    const records = [];
    const emps = INITIAL_EMPLOYEES.filter(e => e.status !== "Inactive");
    for (let d = 0; d < 5; d++) {
        const date = new Date("2026-03-13");
        date.setDate(date.getDate() - d);
        if (date.getDay() === 0 || date.getDay() === 6) continue;
        const dateStr = date.toISOString().split("T")[0];
        emps.forEach((emp, ei) => {
            const seed = (emp.name.charCodeAt(0) + d * 7 + ei * 13) % 100;
            let status = "Present", mode = "Onsite";
            const minSeed = (emp.name.charCodeAt(0) * 3 + d * 11 + ei * 7) % 60;
            let clockIn = `0${8 + (seed % 2 === 0 ? 0 : 0)}:${String(minSeed).padStart(2, "0")}`;
            let clockOut = `${17 + (seed % 3 === 0 ? 0 : 0)}:${String((minSeed + 17) % 60).padStart(2, "0")}`;
            if (seed >= 88) { status = "Absent"; clockIn = "-"; clockOut = "-"; }
            else if (seed >= 78) { status = "Late"; clockIn = `10:${String((minSeed + 23) % 60).padStart(2, "0")}`; }
            if (seed > 50 && seed <= 65) mode = "Remote";
            if (seed > 65 && seed < 78) mode = "Hybrid";
            const hrs = status === "Absent" ? 0 : (7 + (seed % 20) / 10).toFixed(1);
            records.push({ id: `ATT-${emp.id}-${dateStr}`, empId: emp.id, empName: emp.name, date: dateStr, clockIn, clockOut, status, mode, hours: hrs, dept: emp.dept });
        });
    }
    return records;
})();

/* ─── PAYROLL CALCULATION HELPERS ──────────────────────────────────────────
 * Mirror the logic in HRSetupPages.jsx (AllowancePage) so that
 * INITIAL_PAYROLL reflects real plan rates instead of hardcoded percentages.
 * These helpers are also used by buildPayrollApiPayload() below.
 * ────────────────────────────────────────────────────────────────────────── */

/**
 * Returns an array of monthly allowance line-items for a given employee.
 * Rules mirror DEFAULT_ALLOWANCE_TYPES in HRSetupPages.jsx:
 *   al1 Transport  8 000 LKR  fixed   all
 *   al2 Meal       5 000 LKR  fixed   all
 *   al3 Housing   15 % salary percent jf1 jf2 jf3
 *   al4 Phone      3 000 LKR  fixed   jf1 jf6
 *   (al5 Wellness inactive — excluded)
 */
const computeMonthlyAllowances = (emp) => {
    const items = [
        { type: "transport",     label: "Transport Allowance", amount: 8000,                               taxable: false },
        { type: "meal",          label: "Meal Allowance",      amount: 5000,                               taxable: false },
    ];
    if (["jf1", "jf2", "jf3"].includes(emp.familyId))
        items.push({ type: "housing", label: "Housing Allowance", amount: Math.round(emp.salary * 0.15), taxable: true });
    if (["jf1", "jf6"].includes(emp.familyId))
        items.push({ type: "phone_internet", label: "Phone & Internet", amount: 3000,                     taxable: false });
    return items;
};

/**
 * Builds the payroll API payload for a single employee.
 * Sends: country, employment_type, gross_salary, allowances[], bank_details.
 */
const buildPayrollApiPayload = (emp, payRecord) => ({
    employee_id:      emp.id,
    country:          emp.country,
    employment_type:  emp.type,
    gross_salary:     emp.salary,
    currency:         emp.bankDetails?.currency || "LKR",
    allowances: computeMonthlyAllowances(emp).map(a => ({
        type:      a.type,
        label:     a.label,
        amount:    a.amount,
        is_taxable: a.taxable,
        frequency: "monthly",
    })),
    bank_details: emp.bankDetails ? {
        bank_name:            emp.bankDetails.bankName,
        branch_name:          emp.bankDetails.branchName,
        account_number:       emp.bankDetails.accountNumber,
        account_holder_name:  emp.bankDetails.accountHolderName,
        payment_method:       emp.bankDetails.paymentMethod,
        currency:             emp.bankDetails.currency,
    } : null,
    pay_period: payRecord?.period || null,
    net_pay:    payRecord?.netPay  || null,
});

const INITIAL_PAYROLL = INITIAL_EMPLOYEES.filter(e => e.status !== "Inactive").map(emp => {
    const allowanceItems  = computeMonthlyAllowances(emp);
    const totalAllowances = allowanceItems.reduce((s, a) => s + a.amount, 0);
    const deductions      = 0;
    const tax             = Math.floor(emp.salary * 0.12);
    return {
        id:                `PAY-${emp.id}`,
        empId:             emp.id,
        empName:           emp.name,
        dept:              emp.dept,
        country:           emp.country,
        currency:          emp.bankDetails?.currency || "LKR",
        baseSalary:        emp.salary,
        allowances:        totalAllowances,
        allowanceBreakdown: allowanceItems,
        deductions,
        tax,
        netPay:            emp.salary + totalAllowances - deductions - tax,
        status:            emp.name.charCodeAt(0) % 5 === 0 ? "Pending" : "Paid",
        period:            "March 2026",
    };
});

/* Helper: build org tree from flat employees list */
const buildOrgTree = (employees) => {
    const empMap = {};
    employees.forEach(e => { empMap[e.id] = { ...e, children: [] }; });
    const roots = [];
    employees.forEach(e => {
        if (e.managerId && empMap[e.managerId]) {
            empMap[e.managerId].children.push(empMap[e.id]);
        } else {
            roots.push(empMap[e.id]);
        }
    });
    return roots;
};

/* Helper: generate next employee ID */
const nextEmpId = (employees) => {
    const maxNum = employees.reduce((max, e) => {
        const n = parseInt(e.id.replace("EMP", ""), 10);
        return n > max ? n : max;
    }, 0);
    return `EMP${String(maxNum + 1).padStart(3, "0")}`;
};



